/**
 * @munesoft/objx — get
 * Fast, safe deep property access. lodash.get alternative.
 */
import { parsePath } from "../path/index.js";
/**
 * Safely retrieve a deeply nested value from an object using a dot/bracket path.
 *
 * @example
 * get({ a: { b: 1 } }, "a.b")       // 1
 * get({ users: ["Alice"] }, "users[0]") // "Alice"
 * get({}, "a.b.c", "default")         // "default"
 */
export function get(obj, path, fallback) {
    if (obj == null || path === "")
        return fallback;
    const segments = parsePath(path);
    let current = obj;
    for (let i = 0; i < segments.length; i++) {
        if (current == null || typeof current !== "object")
            return fallback;
        current = current[segments[i]];
    }
    return (current === undefined ? fallback : current);
}
/**
 * Compile a path into a reusable getter function.
 * Eliminates repeated path-parsing overhead in hot loops.
 *
 * @example
 * const getName = compile<string>("user.profile.name");
 * getName(obj); // "Alice"
 */
export function compile(path) {
    const segments = parsePath(path); // parse once
    return function compiledGetter(obj, fallback) {
        if (obj == null)
            return fallback;
        let current = obj;
        for (let i = 0; i < segments.length; i++) {
            if (current == null || typeof current !== "object")
                return fallback;
            current = current[segments[i]];
        }
        return (current === undefined ? fallback : current);
    };
}
